import{_ as e,a as t}from"./chunks/webdav在win显示效果.BVTuSvY9.js";import{_ as i,o as n,c as l,a2 as d}from"./chunks/framework.DnrXFDHb.js";const h=JSON.parse('{"title":"WebDAV Site Access (Beta)","description":"","frontmatter":{},"headers":[],"relativePath":"ms-MY/Safety/webdav-site-access.md","filePath":"ms-MY/Safety/webdav-site-access.md","lastUpdated":1781962217000}'),s={name:"ms-MY/Safety/webdav-site-access.md"};function o(r,a,u,p,c,m){return n(),l("div",null,[...a[0]||(a[0]=[d('<h1 id="webdav-site-access-beta" tabindex="-1">WebDAV Site Access (Beta) <a class="header-anchor" href="#webdav-site-access-beta" aria-label="Permalink to &quot;WebDAV Site Access (Beta)&quot;">​</a></h1><p>WebDAV setting dalam Security Settings mendedahkan ImgBed site anda sebagai WebDAV endpoint.</p><p>Selepas diaktifkan, anda boleh menggunakan Windows, macOS, mobile file managers atau mana-mana WebDAV-compatible client untuk browse, upload, delete dan manage ImgBed files seperti remote folder.</p><p>Ini ialah WebDAV access entry untuk site. Ia berbeza daripada WebDAV storage channel dalam Upload Settings. Upload channel menyimpan files dalam third-party WebDAV service. Setting ini membolehkan ImgBed site menyediakan WebDAV access kepada clients.</p><h2 id="di-mana-untuk-configure" tabindex="-1">Di Mana Untuk Configure <a class="header-anchor" href="#di-mana-untuk-configure" aria-label="Permalink to &quot;Di Mana Untuk Configure&quot;">​</a></h2><p>Buka admin panel, kemudian pergi ke:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Security Settings -&gt; WebDAV</span></span></code></pre></div><p>Available settings:</p><ul><li>Enable</li><li>Username</li><li>Password</li><li>Image loading mode</li><li>Default channel</li></ul><h2 id="fungsi-feature-ini" tabindex="-1">Fungsi Feature Ini <a class="header-anchor" href="#fungsi-feature-ini" aria-label="Permalink to &quot;Fungsi Feature Ini&quot;">​</a></h2><p>Selepas WebDAV diaktifkan, ImgBed menyediakan fixed access URL:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/dav</span></span></code></pre></div><p>Gunakan URL ini untuk connect ke ImgBed file directory.</p><p>Use cases yang sesuai:</p><ul><li>Browse ImgBed files terus dari computer file manager.</li><li>Drag images ke WebDAV folder untuk upload.</li><li>Susun ImgBed folders dari local file manager.</li><li>Gunakan WebDAV-compatible software untuk sync atau manage images.</li><li>Access ImgBed content tanpa membuka admin panel.</li></ul><h2 id="settings" tabindex="-1">Settings <a class="header-anchor" href="#settings" aria-label="Permalink to &quot;Settings&quot;">​</a></h2><h3 id="enable" tabindex="-1">Enable <a class="header-anchor" href="#enable" aria-label="Permalink to &quot;Enable&quot;">​</a></h3><p>Menghidupkan WebDAV endpoint.</p><p>Apabila disabled, clients tidak boleh connect melalui WebDAV.</p><h3 id="username-dan-password" tabindex="-1">Username dan Password <a class="header-anchor" href="#username-dan-password" aria-label="Permalink to &quot;Username dan Password&quot;">​</a></h3><p>Credentials ini digunakan oleh WebDAV clients semasa connect.</p><p>Gunakan WebDAV username dan password yang khusus. Jangan guna semula admin password atau upload password.</p><p>Jika username atau password kosong, WebDAV clients tidak dapat connect dengan betul.</p><h3 id="image-loading-mode" tabindex="-1">Image Loading Mode <a class="header-anchor" href="#image-loading-mode" aria-label="Permalink to &quot;Image Loading Mode&quot;">​</a></h3><p>Image loading mode menentukan image URL mana yang WebDAV clients utamakan semasa membaca images.</p><p>Common choices:</p><table tabindex="0"><thead><tr><th>Mode</th><th>Description</th></tr></thead><tbody><tr><td>Smart loading</td><td>ImgBed memilih berdasarkan context. Recommended untuk normal use.</td></tr><tr><td>Original</td><td>Mengutamakan original images.</td></tr><tr><td>Thumbnail</td><td>Mengutamakan thumbnails. Berguna untuk fast preview.</td></tr></tbody></table><p>Jika tidak pasti, kekalkan <code>Smart loading</code>.</p><h3 id="default-channel" tabindex="-1">Default Channel <a class="header-anchor" href="#default-channel" aria-label="Permalink to &quot;Default Channel&quot;">​</a></h3><p>Default channel digunakan untuk WebDAV uploads.</p><p>Apabila anda copy files ke WebDAV directory dari Windows atau client lain, ImgBed upload files tersebut melalui selected default upload channel.</p><p>Jika tiada default channel dipilih, browsing mungkin berfungsi, tetapi uploads boleh gagal.</p><h2 id="mengakses-webdav-dalam-windows-11" tabindex="-1">Mengakses WebDAV Dalam Windows 11 <a class="header-anchor" href="#mengakses-webdav-dalam-windows-11" aria-label="Permalink to &quot;Mengakses WebDAV Dalam Windows 11&quot;">​</a></h2><p>Windows 11 boleh menambah WebDAV sebagai network location.</p><ol><li>Buka <code>This PC</code>.</li><li>Pilih <code>Add a network location</code>.</li><li>Masukkan <code>https://your-domain.com/dav</code>.</li><li>Masukkan WebDAV username dan password apabila diminta.</li><li>Selesaikan wizard. WebDAV directory kemudian boleh dibuka dalam File Explorer.</li></ol><p><img src="'+e+'" alt="Add WebDAV in Windows 11" loading="lazy"></p><p>Selepas ditambah, WebDAV directory muncul dalam Windows File Explorer. Anda boleh open, copy dan manage files seperti folder biasa.</p><p><img src="'+t+'" alt="WebDAV in Windows" loading="lazy"></p><h2 id="supported-operations" tabindex="-1">Supported Operations <a class="header-anchor" href="#supported-operations" aria-label="Permalink to &quot;Supported Operations&quot;">​</a></h2><p>Selepas WebDAV connection berjaya, biasanya anda boleh:</p><ul><li>View files dan folders.</li><li>Upload files.</li><li>Create folders.</li><li>Rename files atau folders.</li><li>Move files.</li><li>Delete files.</li></ul><p>WebDAV sesuai untuk everyday access dan small-scale file management. Untuk large moves, bulk deletes atau organization yang kompleks, gunakan admin panel.</p><h2 id="login-device-management" tabindex="-1">Login Device Management <a class="header-anchor" href="#login-device-management" aria-label="Permalink to &quot;Login Device Management&quot;">​</a></h2><p>Successful WebDAV connections juga muncul di bawah WebDAV tab dalam Login Device Management.</p><p>Anda boleh review WebDAV clients di sana dan force old devices offline apabila perlu.</p><p>Jika WebDAV username atau password ditukar, clients lama perlu sign in semula.</p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="windows-asyik-meminta-username-dan-password" tabindex="-1">Windows Asyik Meminta Username dan Password <a class="header-anchor" href="#windows-asyik-meminta-username-dan-password" aria-label="Permalink to &quot;Windows Asyik Meminta Username dan Password&quot;">​</a></h3><p>Semak:</p><ul><li>URL ialah <code>https://your-domain.com/dav</code>.</li><li>Username dan password sepadan dengan WebDAV settings.</li><li>WebDAV enabled.</li><li>Site boleh diakses melalui HTTPS.</li></ul><h3 id="browsing-berfungsi-tetapi-upload-gagal" tabindex="-1">Browsing Berfungsi, Tetapi Upload Gagal <a class="header-anchor" href="#browsing-berfungsi-tetapi-upload-gagal" aria-label="Permalink to &quot;Browsing Berfungsi, Tetapi Upload Gagal&quot;">​</a></h3><p>Semak <code>Default channel</code>.</p><p>WebDAV uploads memerlukan default upload channel. Jika ia missing, disabled atau misconfigured, uploads boleh gagal.</p><h3 id="access-speed-tidak-stabil" tabindex="-1">Access Speed Tidak Stabil <a class="header-anchor" href="#access-speed-tidak-stabil" aria-label="Permalink to &quot;Access Speed Tidak Stabil&quot;">​</a></h3><p>WebDAV performance bergantung pada client, network, file count dan default upload channel.</p><p>Jika directory mempunyai banyak files, susun ke dalam folders daripada menyimpan terlalu banyak files dalam satu directory.</p><h2 id="security-recommendations" tabindex="-1">Security Recommendations <a class="header-anchor" href="#security-recommendations" aria-label="Permalink to &quot;Security Recommendations&quot;">​</a></h2><ul><li>Gunakan HTTPS untuk WebDAV access.</li><li>Tetapkan strong password.</li><li>Jangan share WebDAV password dengan orang yang tidak dipercayai.</li><li>Matikan WebDAV apabila tidak digunakan.</li><li>Bersihkan unused WebDAV devices secara berkala dalam Login Device Management.</li></ul><h2 id="webdav-upload-file-size" tabindex="-1">WebDAV Upload File Size <a class="header-anchor" href="#webdav-upload-file-size" aria-label="Permalink to &quot;WebDAV Upload File Size&quot;">​</a></h2><p>WebDAV clients tidak menggunakan large-file chunking flow milik browser upload page. Untuk files melebihi suggested limits di bawah, gunakan web upload page.</p><table tabindex="0"><thead><tr><th>Default Upload Channel</th><th style="text-align:right;">Suggested Single-File Limit for WebDAV</th></tr></thead><tbody><tr><td>Telegram</td><td style="text-align:right;">20 MB</td></tr><tr><td>Discord</td><td style="text-align:right;">10 MB</td></tr><tr><td>Cloudflare R2</td><td style="text-align:right;">30 MB</td></tr><tr><td>S3</td><td style="text-align:right;">30 MB</td></tr><tr><td>GitHub Releases</td><td style="text-align:right;">64 MB</td></tr><tr><td>GitLab Packages</td><td style="text-align:right;">64 MB</td></tr><tr><td>Hugging Face</td><td style="text-align:right;">20 MB</td></tr><tr><td>OneDrive</td><td style="text-align:right;">30 MB</td></tr><tr><td>Google Drive</td><td style="text-align:right;">30 MB</td></tr><tr><td>Dropbox</td><td style="text-align:right;">30 MB</td></tr><tr><td>Yandex Disk</td><td style="text-align:right;">30 MB</td></tr><tr><td>pCloud</td><td style="text-align:right;">30 MB</td></tr><tr><td>WebDAV</td><td style="text-align:right;">64 MB</td></tr></tbody></table>',61)])])}const k=i(s,[["render",o]]);export{h as __pageData,k as default};
